class Solution {
    public List<List<String>> accountsMerge(List<List<String>> accounts) {
        Map<String, String> parent = new HashMap<>();
        Map<String, String> owner = new HashMap<>();
        for (List<String> account : accounts) {
            String name = account.get(0);
            for (int i = 1; i < account.size(); i++) {
                String email = account.get(i);
                parent.putIfAbsent(email, email);
                owner.put(email, name);
                if (i > 1) union(parent, account.get(1), email);
            }
        }
        Map<String, TreeSet<String>> groups = new HashMap<>();
        for (String email : parent.keySet()) {
            String root = find(parent, email);
            groups.computeIfAbsent(root, k -> new TreeSet<>()).add(email);
        }
        List<List<String>> result = new ArrayList<>();
        for (var entry : groups.entrySet()) {
            List<String> merged = new ArrayList<>();
            merged.add(owner.get(entry.getKey()));
            merged.addAll(entry.getValue());
            result.add(merged);
        }
        return result;
    }
    private String find(Map<String, String> parent, String x) {
        if (!parent.get(x).equals(x)) parent.put(x, find(parent, parent.get(x)));
        return parent.get(x);
    }
    private void union(Map<String, String> parent, String a, String b) {
        parent.put(find(parent, a), find(parent, b));
    }
}

class Solution {
    public List<List<String>> accountsMerge(List<List<String>> accounts) {
        Map<String, List<String>> graph = new HashMap<>();
        Map<String, String> owner = new HashMap<>();
        for (List<String> account : accounts) {
            String name = account.get(0);
            for (int i = 1; i < account.size(); i++) {
                String email = account.get(i);
                owner.put(email, name);
                graph.computeIfAbsent(account.get(1), k -> new ArrayList<>()).add(email);
                graph.computeIfAbsent(email, k -> new ArrayList<>()).add(account.get(1));
            }
        }
        Set<String> visited = new HashSet<>();
        List<List<String>> result = new ArrayList<>();
        for (String email : owner.keySet()) {
            if (!visited.contains(email)) {
                List<String> component = new ArrayList<>();
                dfs(graph, email, visited, component);
                Collections.sort(component);
                component.add(0, owner.get(email));
                result.add(component);
            }
        }
        return result;
    }
    private void dfs(Map<String, List<String>> graph, String email, Set<String> visited, List<String> component) {
        visited.add(email);
        component.add(email);
        for (String nei : graph.getOrDefault(email, new ArrayList<>())) {
            if (!visited.contains(nei)) {
                dfs(graph, nei, visited, component);
            }
        }
    }
}
